patch:
--- a/alu_16bit.v
+++ b/alu_16bit.v
@@ -10,7 +10,7 @@
   output [15:0] result
 );

-  always @(operand_a or alu_op)
+  always @(*)
   begin
     case(alu_op)
       4'h0: result = operand_a + operand_b;

before_code:
module alu_16bit (
  input [15:0] operand_a,
  input [15:0] operand_b,
  input [3:0] alu_op,
  output [15:0] result
);

  always @(operand_a or alu_op)
  begin
    case(alu_op)
      4'h0: result = operand_a + operand_b;
      4'h1: result = operand_a - operand_b;
      4'h2: result = operand_a & operand_b;
      4'h3: result = operand_a | operand_b;
      4'h4: result = operand_a ^ operand_b;
      default: result = 16'h0000;
    endcase
  end

endmodule

after_code:
module alu_16bit (
  input [15:0] operand_a,
  input [15:0] operand_b,
  input [3:0] alu_op,
  output [15:0] result
);

  always @(*)
  begin
    case(alu_op)
      4'h0: result = operand_a + operand_b;
      4'h1: result = operand_a - operand_b;
      4'h2: result = operand_a & operand_b;
      4'h3: result = operand_a | operand_b;
      4'h4: result = operand_a ^ operand_b;
      default: result = 16'h0000;
    endcase
  end

endmodule
